import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertTrue(original.getIgnoreEmptyLines()); // DEFAULT has ignoreEmptyLines=true

        CSVFormat modified = original.withIgnoreEmptyLines();
        assertNotNull(modified);
        assertTrue(modified.getIgnoreEmptyLines());
        // The original should remain unchanged (immutability)
        assertTrue(original.getIgnoreEmptyLines());

        // Also test withIgnoreEmptyLines(false) to verify difference
        CSVFormat disabled = original.withIgnoreEmptyLines(false);
        assertNotNull(disabled);
        assertFalse(disabled.getIgnoreEmptyLines());
    }
}
